type Item = { type: string };
type Scenario = {
  steps: Array<{ op: string; items?: Item[] }>;
};

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.1;
const BASE_PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
  rune: 25,
};

export function processScenario(scenario: unknown): unknown {
  const { steps } = scenario as Scenario;
  const results = steps.map((step) => {
    const items = step.items ?? [];
    const base = items.reduce(
      (sum, item) => sum + BASE_PREMIUM_BY_ITEM_TYPE[item.type],
      0,
    );
    const premium =
      items.length === 0
        ? PROCESSING_FEE
        : Math.ceil(base * (1 + FIRST_INSURANCE_RATE)) + PROCESSING_FEE;
    return { premium };
  });
  return { results };
}

